INSERT INTO app_updates (title, description, update_type, version, is_active, created_at) VALUES 
('Vibrant Color Palette Update', 'Completely redesigned the color scheme with bright, vibrant colors that work beautifully in both light and dark modes. The new palette features coral/pink primaries, vibrant purple secondaries, electric blue accents, and deep rich tones for dark mode, creating a modern and energetic visual experience.', 'improvement', '3.2.0', true, '2025-11-03 00:10:00'),
('Enhanced Password Security', 'Implemented encrypted password storage for both account credentials and SIM card login details using secure encryption functions. All passwords are now encrypted before being saved to the database and decrypted only when needed, significantly improving data security.', 'security', '3.1.0', true, '2025-11-02 00:00:00'),
('Intelligent SIM Card Filtering', 'Inactive, swapped, and expired SIM cards are now automatically hidden from the default view to reduce clutter. These records only appear when they match your search criteria, making it easier to find current active SIM cards while still preserving access to historical data when needed.', 'feature', '3.0.0', true, '2025-11-03 00:09:00'),
('Passkey Authentication Support', 'Added support for passkey-based authentication, allowing users to sign in using biometric authentication or security keys. This modern authentication method provides enhanced security and a seamless login experience across devices.', 'feature', '2.9.0', true, '2025-10-15 00:00:00'),
('Multi-Factor Authentication (MFA)', 'Introduced comprehensive two-factor authentication with TOTP support. Users can now enable MFA using authenticator apps like Google Authenticator or Authy, with backup codes provided for account recovery. This adds an extra layer of security to protect your account.', 'security', '2.8.0', true, '2025-09-20 00:00:00'),
('Security Enhancements', 'Removed sensitive data logging from browser console to prevent credential exposure. Implemented proper security practices throughout the authentication flow to protect user data from potential security vulnerabilities.', 'security', '2.7.0', true, '2025-11-02 00:00:00'),
('Performance Optimizations', 'Optimized profile data fetching to reduce unnecessary database queries. The app now makes fewer redundant requests, resulting in faster page loads and improved overall performance.', 'improvement', '2.6.0', true, '2025-10-01 00:00:00');